from playwright.sync_api import Page, sync_playwright
from typing import Any


class BrowserToolkit:
    """Wraps Playwright operations as discrete tool functions for an AI agent.

    Each method maps directly to one tool call the LLM can issue.
    Returning a dict (not raw text) lets the agent parse structured state.
    """

    def __init__(self, headless: bool = True):
        self._pw = sync_playwright().start()
        self._browser = self._pw.chromium.launch(headless=headless)
        self._page: Page = self._browser.new_page()

    def navigate(self, url: str) -> dict[str, Any]:
        self._page.goto(url, wait_until="domcontentloaded")
        return {"url": self._page.url, "title": self._page.title()}

    def click(self, selector: str) -> dict[str, Any]:
        self._page.click(selector)
        self._page.wait_for_load_state("networkidle")
        return {"clicked": selector, "current_url": self._page.url}

    def fill_field(self, selector: str, value: str) -> dict[str, Any]:
        self._page.fill(selector, value)
        return {"filled": selector}

    def extract_text(self, selector: str) -> dict[str, Any]:
        text = self._page.inner_text(selector)
        return {"selector": selector, "text": text}

    def screenshot(self) -> bytes:
        return self._page.screenshot()

    def close(self) -> None:
        self._browser.close()
        self._pw.stop()
